import sys
import functools

def main():
    N = int(sys.stdin.readline())
    size = 3 ** N

    @functools.lru_cache(maxsize=None)
    def is_black(x, y, level):
        if level == 0:
            return True
        block_size = 3 ** (level - 1)
        x_block, y_block = x // block_size, y // block_size
        if x_block == 1 and y_block == 1:
            return False
        return is_black(x % block_size, y % block_size, level - 1)

    result = []
    for i in range(size):
        row = []
        for j in range(size):
            if is_black(i, j, N):
                row.append('#')
            else:
                row.append('.')
        result.append(''.join(row))
    print('\n'.join(result))

if __name__ == "__main__":
    main()
